use std::process::{Command, Stdio};
use std::path::PathBuf;

fn convert_file(filename: &str, desired_format: &str) -> Result<PathBuf, String> {
    let input_path = PathBuf::from(filename);
    let output_filename = format!("{}.{}", input_path.file_stem().unwrap().to_str().unwrap(), desired_format);
    let output_path = input_path.with_file_name(output_filename);

    if !input_path.exists() {
        return Err(format!("File not found: {}", filename));
    }

    match desired_format {
        "pdf" => {
            Command::new("pdftk")
                .args(&[filename, "output", &output_path.to_string_lossy()])
                .stdout(Stdio::null())
                .stderr(Stdio::null())
                .status()
                .map_err(|e| format!("Failed to run pdftk: {}", e))?;
        }
        "jpg" => {
            Command::new("convert")
                .args(&[filename, &output_path.to_string_lossy()])
                .stdout(Stdio::null())
                .stderr(Stdio::null())
                .status()
                .map_err(|e| format!("Failed to run convert: {}", e))?;
        }
        _ => return Err(format!("Unsupported format: {}", desired_format)),
    }

    Ok(output_path)
}